// typeof narrows primitive unions
function process(value: string | number | boolean): string {
  if (typeof value === 'string')  return value.toUpperCase();
  if (typeof value === 'number')  return value.toFixed(2);
  return String(value); // value: boolean here
}

// instanceof narrows class instances
class Cat { meow(): void { console.log('meow'); } }
class Dog { bark(): void { console.log('woof'); } }

function makeSound(pet: Cat | Dog): void {
  if (pet instanceof Cat) {
    pet.meow(); // pet: Cat
  } else {
    pet.bark(); // pet: Dog
  }
}

// Exhaustive typeof values
const testCases = {
  string:    typeof 'hello',           // 'string'
  number:    typeof 42,                // 'number'
  boolean:   typeof true,              // 'boolean'
  undefined: typeof undefined,         // 'undefined'
  symbol:    typeof Symbol('s'),       // 'symbol'
  bigint:    typeof 9007199254740993n, // 'bigint'
  object:    typeof { a: 1 },         // 'object'
  nullBug:   typeof null,              // 'object'  <-- quirk
  array:     typeof [1, 2, 3],        // 'object'  <-- arrays are objects
  fn:        typeof (() => {}),        // 'function'
};

// TypeScript inference from typeof
function doubleIfNumber(x: string | number): string | number {
  if (typeof x === 'number') {
    return x * 2; // x: number — arithmetic allowed
  }
  return x;       // x: string
}

// typeof is the primary tool for narrowing unknown
function parse(raw: unknown): number {
  if (typeof raw === 'number') return raw; // raw: number
  if (typeof raw === 'string') {
    const n = Number(raw);
    if (!isNaN(n)) return n;
  }
  throw new TypeError(`Cannot convert to number: ${raw}`);
}

// Check for object before accessing properties on unknown
function getProperty(raw: unknown, key: string): unknown {
  if (typeof raw === 'object' && raw !== null && key in raw) {
    return (raw as Record<string, unknown>)[key];
  }
  return undefined;
}

// Real-world: environment variable narrowing
const port = process.env.PORT;
// typeof port === 'string' | 'undefined'
const portNum = typeof port === 'string' ? parseInt(port, 10) : 3000;

// typeof null === 'object' — always null-guard after an object check
function processObj(value: object | null | undefined): string {
  if (typeof value === 'object') {
    // value is still object | null here — typeof null === 'object'
    if (value !== null) {
      return JSON.stringify(value); // value: object — null excluded
    }
    return '(null)';
  }
  return '(undefined)';
}

// Idiomatic combined check
function isPlainObject(x: unknown): x is Record<string, unknown> {
  return typeof x === 'object' && x !== null && !Array.isArray(x);
}

// Angular: type-safe access to component inputs before they are set
function getValue(input: string | null | undefined): string {
  if (typeof input === 'string') return input;
  return '';
}

class Animal { constructor(public name: string) {} }
class Dog extends Animal {
  constructor(name: string, public breed: string) { super(name); }
  bark(): void { console.log('Woof!'); }
}
class Cat extends Animal {
  constructor(name: string, public indoor: boolean) { super(name); }
  meow(): void { console.log('Meow!'); }
}

const rex = new Dog('Rex', 'Labrador');

// instanceof is true for all classes in the prototype chain
console.log(rex instanceof Dog);    // true — direct class
console.log(rex instanceof Animal); // true — parent class
console.log(rex instanceof Object); // true — Object.prototype at the top
console.log(rex instanceof Cat);    // false — not in the chain

// TypeScript narrows to the first matching class
function describe(pet: Animal): string {
  if (pet instanceof Dog) {
    // pet: Dog — breed and bark() are available
    return `Dog: ${pet.name} (${pet.breed})`;
  }
  if (pet instanceof Cat) {
    // pet: Cat — indoor and meow() are available
    return `Cat: ${pet.name} (${pet.indoor ? 'indoor' : 'outdoor'})`;
  }
  return `Animal: ${pet.name}`;
}

class AppError extends Error {
  constructor(message: string, public readonly code: string) {
    super(message);
    this.name = 'AppError';
  }
}

class NetworkError extends AppError {
  constructor(message: string, public readonly statusCode: number) {
    super(message, 'NETWORK_ERROR');
  }
}

class AuthError extends AppError {
  constructor(message: string) {
    super(message, 'AUTH_ERROR');
  }
}

function handleError(err: unknown): string {
  if (err instanceof NetworkError) {
    // err: NetworkError — statusCode available
    return `Network error ${err.statusCode}: ${err.message}`;
  }
  if (err instanceof AuthError) {
    // err: AuthError — redirect to login
    return `Auth error: ${err.message}`;
  }
  if (err instanceof AppError) {
    // err: AppError — generic app error
    return `App error [${err.code}]: ${err.message}`;
  }
  if (err instanceof Error) {
    return `Unknown error: ${err.message}`;
  }
  return 'Non-error thrown';
}

// Usage in an Angular service
try {
  // ... some HTTP call
} catch (e) {
  const message = handleError(e);
  // display message to the user
}

type ApiInput = string | number | Error | { data: unknown };

function process(input: ApiInput): string {
  // Order matters — check most specific first
  if (input instanceof Error) {
    // input: Error — message available
    return `Error: ${input.message}`;
  }

  if (typeof input === 'string') {
    // input: string
    return input.trim();
  }

  if (typeof input === 'number') {
    // input: number
    return input.toFixed(2);
  }

  // input: { data: unknown } — the remaining union member
  return JSON.stringify(input.data);
}

// Angular interceptor pattern — using both in an error handler
import { HttpErrorResponse } from '@angular/common/http';

function describeHttpError(err: unknown): string {
  if (err instanceof HttpErrorResponse) {
    // err: HttpErrorResponse — Angular specific
    return `HTTP ${err.status}: ${err.statusText}`;
  }
  if (err instanceof Error) {
    return err.message;
  }
  if (typeof err === 'string') {
    return err;
  }
  return 'Unknown error';
}

// When JavaScript code runs in multiple realms (iframes, workers),
// each realm has its own Array/Error/etc constructors.
// An array from another realm fails instanceof Array in the main realm.

// Use Array.isArray() instead — it works across realms
function isArray(v: unknown): v is unknown[] {
  return Array.isArray(v); // NOT: v instanceof Array
}

// Similarly for plain objects — use Object.prototype.toString
function isPlainObj(v: unknown): v is Record<string, unknown> {
  return Object.prototype.toString.call(v) === '[object Object]';
}

// typeof cannot tell Date from Map from a plain object
const d = new Date();
const m = new Map();
const o = { key: 'value' };

console.log(typeof d); // 'object'
console.log(typeof m); // 'object'
console.log(typeof o); // 'object'

// Use instanceof for class discrimination
function isDate(v: unknown): v is Date { return v instanceof Date; }
function isMap(v: unknown): v is Map<unknown, unknown> { return v instanceof Map; }

// Angular: checking TemplateRef vs ElementRef
import { TemplateRef, ElementRef } from '@angular/core';

function isTemplateRef(value: TemplateRef<unknown> | ElementRef): value is TemplateRef<unknown> {
  return value instanceof TemplateRef;
}

type Primitive = string | number | boolean | null | undefined;

function toPrettyString(value: Primitive): string {
  if (value === null)       return '(null)';
  if (value === undefined)  return '(undefined)';
  if (typeof value === 'boolean') return value ? 'Yes' : 'No';
  if (typeof value === 'number')  return value.toLocaleString();
  // value: string — only remaining type
  return value;
}

// Switch version — cleaner for many branches
type JsonPrimitive = string | number | boolean | null;

function jsonToDisplay(val: JsonPrimitive): string {
  switch (typeof val) {
    case 'string':  return `"${val}"`;
    case 'number':  return val.toFixed(4);
    case 'boolean': return val ? 'true' : 'false';
    case 'object':  return 'null'; // typeof null === 'object'
  }
}
// TypeScript reports exhaustiveness — if val had another member,
// switch would have an implicit return (missing case).

abstract class Widget {
  abstract render(): string;
  get type(): string { return this.constructor.name; }
}

class TextWidget extends Widget {
  constructor(public text: string) { super(); }
  render(): string { return `<span>${this.text}</span>`; }
  uppercase(): string { return this.text.toUpperCase(); } // TextWidget-only method
}

class ImageWidget extends Widget {
  constructor(public src: string, public alt: string) { super(); }
  render(): string { return `<img src="${this.src}" alt="${this.alt}"/>` ; }
  getDimensions(): { w: number; h: number } { return { w: 0, h: 0 }; } // ImageWidget-only
}

class ContainerWidget extends Widget {
  constructor(public children: Widget[]) { super(); }
  render(): string { return `<div>${this.children.map(c => c.render()).join('')}</div>`; }
  addChild(child: Widget): void { this.children.push(child); }
}

type AnyWidget = TextWidget | ImageWidget | ContainerWidget;

function processWidget(widget: AnyWidget): void {
  // Polymorphic dispatch — always works via abstract render()
  console.log(widget.render());

  // instanceof for subclass-specific behaviour
  if (widget instanceof TextWidget) {
    console.log(widget.uppercase()); // TextWidget-specific method
  } else if (widget instanceof ContainerWidget) {
    console.log(`Container with ${widget.children.length} children`);
  }
}

import { Injectable } from '@angular/core';
import { HttpErrorResponse } from '@angular/common/http';
import { Observable, catchError, throwError } from 'rxjs';

@Injectable({ providedIn: 'root' })
class ErrorHandlerService {
  handle(err: unknown): Observable<never> {
    // instanceof first — most specific Angular error type
    if (err instanceof HttpErrorResponse) {
      if (err.status === 401) {
        return throwError(() => new Error('Session expired. Please log in again.'));
      }
      if (err.status === 403) {
        return throwError(() => new Error('You do not have permission to perform this action.'));
      }
      if (err.status >= 500) {
        return throwError(() => new Error('A server error occurred. Please try again later.'));
      }
      return throwError(() => new Error(`HTTP error ${err.status}: ${err.statusText}`));
    }

    // Generic JavaScript Error
    if (err instanceof Error) {
      return throwError(() => err);
    }

    // String thrown directly — bad practice but happens in third-party code
    if (typeof err === 'string') {
      return throwError(() => new Error(err));
    }

    // Fallback for anything else
    return throwError(() => new Error('An unexpected error occurred.'));
  }
}

// Angular + Node.js build process — environment type checks
// environment.ts
export const environment = {
  production: false,
  apiUrl: 'http://localhost:3000',
  featureFlags: {
    newDashboard: true,
    betaSearch: false,
  },
};

// Type-safe env var access
function getApiUrl(): string {
  const url = environment.apiUrl;
  if (typeof url !== 'string' || url.length === 0) {
    throw new Error('API URL is not configured');
  }
  return url;
}

// Checking injected config tokens
import { InjectionToken, inject } from '@angular/core';

const CONFIG = new InjectionToken<Record<string, unknown>>('AppConfig');

function getConfigValue(key: string): string {
  const config = inject(CONFIG);
  const value = config[key];
  if (typeof value !== 'string') {
    throw new Error(`Config key "${key}" is not a string`);
  }
  return value;
}

// Unit testing narrowing logic
describe('typeof narrowing', () => {
  function format(v: string | number): string {
    if (typeof v === 'string') return v.trim();
    return v.toFixed(2);
  }

  it('trims strings', () => {
    expect(format('  hello  ')).toBe('hello');
  });

  it('formats numbers to 2 decimal places', () => {
    expect(format(3.14159)).toBe('3.14');
  });
});

// Testing instanceof error handling
class AppError extends Error {
  constructor(public code: string, message: string) {
    super(message);
  }
}

function parseCode(err: unknown): string {
  if (err instanceof AppError) return err.code;
  if (err instanceof Error)    return 'UNKNOWN';
  return 'NON_ERROR';
}

describe('instanceof error narrowing', () => {
  it('extracts code from AppError', () => {
    expect(parseCode(new AppError('E001', 'oops'))).toBe('E001');
  });

  it('returns UNKNOWN for generic Error', () => {
    expect(parseCode(new Error('plain'))).toBe('UNKNOWN');
  });

  it('returns NON_ERROR for non-Error throws', () => {
    expect(parseCode('string thrown')).toBe('NON_ERROR');
  });
});
